export async function render(item, api) {
  const container = api.createElement('div', { 
    class: 'note-view',
    style: 'max-width: 800px; margin: 0 auto;'
  }, []);

  // Header section
  const header = api.createElement('div', { 
    style: 'margin-bottom: 20px; padding-bottom: 15px; border-bottom: 2px solid #e0e0e0;' 
  }, []);

  // Title (editable)
  const titleInput = api.createElement('input', {
    type: 'text',
    value: item.content.title || '',
    placeholder: 'Untitled Note',
    style: 'width: 100%; font-size: 24px; font-weight: bold; border: none; outline: none; padding: 8px 0; background: transparent;',
    onchange: async (e) => {
      const updated = {
        ...item,
        content: {
          ...item.content,
          title: e.target.value
        }
      };
      await api.update(updated);
    }
  }, []);
  header.appendChild(titleInput);

  // Metadata
  const meta = api.createElement('div', { 
    style: 'margin-top: 8px; font-size: 12px; color: #999;' 
  }, [
    'Modified: ' + new Date(item.modified).toLocaleString()
  ]);
  header.appendChild(meta);

  container.appendChild(header);

  // Body section with view/edit toggle
  let isEditing = false;
  let currentTextarea = null;
  const bodyContainer = api.createElement('div', {}, []);

  const renderBody = async () => {
    bodyContainer.innerHTML = '';

    if (isEditing) {
      // Edit mode: textarea
      const textarea = api.createElement('textarea', {
        style: 'width: 100%; min-height: 400px; font-family: monospace; font-size: 14px; line-height: 1.6; padding: 15px; border: 1px solid #d0d0d0; border-radius: 6px; resize: vertical;',
        spellcheck: false
      }, []);
      textarea.value = item.content.body || '';
      currentTextarea = textarea;

      // Tab key handling
      textarea.addEventListener('keydown', (e) => {
        if (e.key === 'Tab') {
          e.preventDefault();
          const start = textarea.selectionStart;
          const end = textarea.selectionEnd;
          textarea.value = textarea.value.substring(0, start) + '  ' + textarea.value.substring(end);
          textarea.selectionStart = textarea.selectionEnd = start + 2;
        }
      });

      bodyContainer.appendChild(textarea);

      // Buttons
      const buttons = api.createElement('div', { 
        style: 'margin-top: 15px; display: flex; gap: 10px; flex-wrap: wrap;' 
      }, []);

      const saveBtn = api.createElement('button', {
        style: 'padding: 10px 20px; cursor: pointer; font-weight: 500;',
        onclick: async () => {
          const updated = {
            ...item,
            content: {
              ...item.content,
              body: textarea.value
            }
          };
          await api.update(updated);
          isEditing = false;
          await renderBody();
        }
      }, ['Save']);
      buttons.appendChild(saveBtn);

      const cancelBtn = api.createElement('button', {
        style: 'padding: 10px 20px; cursor: pointer;',
        onclick: async () => {
          isEditing = false;
          await renderBody();
        }
      }, ['Cancel']);
      buttons.appendChild(cancelBtn);

      // INSERT LINK button - the new feature!
      const insertLinkBtn = api.createElement('button', {
        style: 'padding: 10px 20px; cursor: pointer; background: #28a745; color: white; border: none; border-radius: 4px;',
        onclick: () => showLinkPicker()
      }, ['Insert Link']);
      buttons.appendChild(insertLinkBtn);

      bodyContainer.appendChild(buttons);

      // Link picker UI (hidden by default)
      const pickerContainer = api.createElement('div', {
        style: 'display: none; margin-top: 15px; padding: 15px; border: 1px solid #ddd; border-radius: 6px; background: #f9f9f9;'
      }, []);

      const pickerTitle = api.createElement('h4', {
        style: 'margin: 0 0 10px 0;'
      }, ['Recent Items']);
      pickerContainer.appendChild(pickerTitle);

      const pickerList = api.createElement('div', {
        style: 'max-height: 300px; overflow-y: auto;'
      }, []);
      pickerContainer.appendChild(pickerList);

      const pickerClose = api.createElement('button', {
        style: 'margin-top: 10px; padding: 8px 16px; cursor: pointer;',
        onclick: () => {
          pickerContainer.style.display = 'none';
        }
      }, ['Close']);
      pickerContainer.appendChild(pickerClose);

      bodyContainer.appendChild(pickerContainer);

      // Show link picker
      const showLinkPicker = () => {
        pickerList.innerHTML = '';

        // Get recent items from kernel
        const recent = window.kernel.getRecentItems();

        if (recent.length === 0) {
          pickerList.appendChild(api.createElement('div', {
            style: 'padding: 20px; text-align: center; color: #999;'
          }, ['No recent items. Navigate to some items first!']));
        } else {
          // Show most recent first
          const reversed = recent.slice().reverse();

          reversed.forEach(recentItem => {
            const itemBtn = api.createElement('div', {
              style: 'padding: 10px; margin-bottom: 5px; background: white; border: 1px solid #ddd; border-radius: 4px; cursor: pointer; transition: background 0.2s;',
              onclick: () => insertLink(recentItem.id, recentItem.name),
              onmouseover: (e) => { e.target.style.background = '#f0f0f0'; },
              onmouseout: (e) => { e.target.style.background = 'white'; }
            }, [recentItem.name]);
            pickerList.appendChild(itemBtn);
          });
        }

        pickerContainer.style.display = 'block';
      };

      // Insert link at cursor position
      const insertLink = (targetId, targetName) => {
        const textarea = currentTextarea;
        const start = textarea.selectionStart;
        const end = textarea.selectionEnd;

        // Create markdown link
        const linkText = '[' + targetName + '](item://' + targetId + ')';

        // Insert at cursor
        textarea.value = textarea.value.substring(0, start) + linkText + textarea.value.substring(end);

        // Move cursor to after inserted link
        textarea.selectionStart = textarea.selectionEnd = start + linkText.length;

        // Hide picker
        pickerContainer.style.display = 'none';

        // Focus back on textarea
        textarea.focus();
      };

    } else {
      // View mode: rendered markdown
      const body = item.content.body || '*No content yet. Click Edit to add some.*';

      // Parse markdown
      const marked = await api.require('marked');
      const html = marked.default.parse(body);

      // Create content div
      const content = api.createElement('div', {
        class: 'markdown-content',
        style: 'line-height: 1.8; font-size: 16px;'
      }, []);
      content.innerHTML = html;

      // Post-process: handle item:// links
      const links = content.querySelectorAll('a[href^="item://"]');
      links.forEach(link => {
        const href = link.getAttribute('href');
        const itemId = href.replace('item://', '');

        // Override click behavior
        link.onclick = (e) => {
          e.preventDefault();
          api.openSibling(itemId);
        };  

        // Style internal links
        link.style.color = '#007bff';
        link.style.textDecoration = 'none';
        link.style.borderBottom = '1px solid #007bff';
        link.style.cursor = 'pointer';
      });

      bodyContainer.appendChild(content);

      // Edit button
      const editBtn = api.createElement('button', {
        style: 'margin-top: 20px; padding: 10px 20px; cursor: pointer;',
        onclick: () => {
          isEditing = true;
          renderBody();
        }
      }, ['Edit']);
      bodyContainer.appendChild(editBtn);
    }
  };

  await renderBody();
  container.appendChild(bodyContainer);

  return container;
}

export async function render(item, api) {
  const container = api.createElement('div', { style: 'padding: 15px;' }, []);

  // Header
  const header = api.createElement('h3', { style: 'margin-top: 0;' }, [
    item.name || 'Untitled Script'
  ]);
  container.appendChild(header);

  // Description
  if (item.content.description) {
    const desc = api.createElement('p', { style: 'color: #666; font-style: italic;' }, [
      item.content.description
    ]);
    container.appendChild(desc);
  }

  // Code display
  const code = api.createElement('pre', {
    style: `
      background: #f8f8f8;
      padding: 15px;
      border-radius: 4px;
      border: 1px solid #ddd;
      overflow-x: auto;
      font-family: 'SF Mono', Monaco, monospace;
      font-size: 13px;
      line-height: 1.5;
    `
  }, [item.content.code || '// No code']);
  container.appendChild(code);

  // Buttons
  const buttons = api.createElement('div', { 
    style: 'margin-top: 15px; display: flex; gap: 10px;' 
  }, []);

  const runBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px; font-weight: 500;',
    onclick: async () => {
      runBtn.disabled = true;
      runBtn.textContent = 'Running...';

      try {
        // Get the REPL API which has the helper functions
        const replApi = window.kernel.createREPLAPI();

        // Execute the script code with REPL API
        const asyncFn = new Function('api', `
          return (async () => {
            ${item.content.code}
          })();
        `);

        const result = await asyncFn(replApi);
        alert('Script executed!\n\nResult: ' + (
          result !== undefined 
            ? JSON.stringify(result, null, 2) 
            : 'No return value'
        ));
      } catch (error) {
        alert('Error executing script:\n\n' + error.message);
      } finally {
        runBtn.disabled = false;
        runBtn.textContent = 'Run Script';
      }
    }
  }, ['Run Script']);
  buttons.appendChild(runBtn);

  const editBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer;',
    onclick: () => {
      // Navigate to raw editor for this item
      window.kernel.editItemRaw(item.id);
    }
  }, ['Edit']);
  buttons.appendChild(editBtn);

  const copyBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer;',
    onclick: () => {
      navigator.clipboard.writeText(item.content.code);
      copyBtn.textContent = 'Copied!';
      setTimeout(() => copyBtn.textContent = 'Copy Code', 1000);
    }
  }, ['Copy Code']);
  buttons.appendChild(copyBtn);

  container.appendChild(buttons);

  return container;
}

// Minimal marked.js implementation - just what we need
// Full library: https://cdn.jsdelivr.net/npm/marked@11.1.1/marked.min.js

const marked = (() => {
  const block = {
    newline: /^\n+/,
    code: /^( {4}[^\n]+\n*)+/,
    heading: /^ {0,3}(#{1,6})(?=\s|$)(.*)(?:\n+|$)/,
    hr: /^ {0,3}((?:- *){3,}|(?:_ *){3,}|(?:\* *){3,})(?:\n+|$)/,
    blockquote: /^( {0,3}> ?(>| )?(.*(?:\n(?! {0,3}\[)[^\n]+)*)(?:\n+|$))+/,
    list: /^( {0,3})(bull) [\s\S]+?(?:hr|def|\n{2,}(?! )(?!\1bull )\n*|\s*$)/,
    paragraph: /^([^\n]+(?:\n(?!hr|heading|blockquote)[^\n]+)*)/,
    text: /^[^\n]+/
  };

  const inline = {
    escape: /^\\([!"#$%&'()*+,\-./:;<=>?@\[\\\]^_`{|}~])/,
    link: /^!?\[((?:\[[^\]]*\]|[^\[\]]|\](?=[^\[]*\]))*)\]\(\s*<?(.*?)>?(?:\s+['"](.*?)['"])?\s*\)/,
    strong: /^__(.*?)__(?!_)|^\*\*(.*?)\*\*(?!\*)/,
    em: /^\b_((?:__|[^_])+?)_\b|^\*((?:\*\*|[^\*])+?)\*(?!\*)/,
    code: /^`([^`]|[^`][\s\S]*?[^`])`/,
    br: /^ {2,}\n(?!\s*$)/,
    text: /^[\s\S]+?(?=[\\<!\[_*`]| {2,}\n|$)/
  };

  function escape(html) {
    return html
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function parseInline(src) {
    let out = '';
    let cap;

    while (src) {
      // escape
      if (cap = inline.escape.exec(src)) {
        src = src.substring(cap[0].length);
        out += escape(cap[1]);
        continue;
      }

      // link
      if (cap = inline.link.exec(src)) {
        src = src.substring(cap[0].length);
        const text = cap[1];
        const href = cap[2];
        out += '<a href="' + escape(href) + '">' + parseInline(text) + '</a>';
        continue;
      }

      // strong
      if (cap = inline.strong.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<strong>' + parseInline(cap[2] || cap[1]) + '</strong>';
        continue;
      }

      // em
      if (cap = inline.em.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<em>' + parseInline(cap[2] || cap[1]) + '</em>';
        continue;
      }

      // code
      if (cap = inline.code.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<code>' + escape(cap[1].trim()) + '</code>';
        continue;
      }

      // br
      if (cap = inline.br.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<br>';
        continue;
      }

      // text
      if (cap = inline.text.exec(src)) {
        src = src.substring(cap[0].length);
        out += escape(cap[0]);
        continue;
      }

      if (src) {
        throw new Error('Infinite loop on byte: ' + src.charCodeAt(0));
      }
    }

    return out;
  }

  function parse(src) {
    let out = '';
    let cap;

    src = src.replace(/\r\n|\r/g, '\n').replace(/\t/g, '    ');

    while (src) {
      // newline
      if (cap = block.newline.exec(src)) {
        src = src.substring(cap[0].length);
        continue;
      }

      // code block
      if (cap = block.code.exec(src)) {
        src = src.substring(cap[0].length);
        const code = cap[0].replace(/^ {4}/gm, '');
        out += '<pre><code>' + escape(code.trim()) + '</code></pre>\n';
        continue;
      }

      // heading
      if (cap = block.heading.exec(src)) {
        src = src.substring(cap[0].length);
        const level = cap[1].length;
        const text = cap[2].trim();
        out += '<h' + level + '>' + parseInline(text) + '</h' + level + '>\n';
        continue;
      }

      // hr
      if (cap = block.hr.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<hr>\n';
        continue;
      }

      // blockquote
      if (cap = block.blockquote.exec(src)) {
        src = src.substring(cap[0].length);
        const quote = cap[0].replace(/^ *> ?/gm, '');
        out += '<blockquote>\n' + parse(quote) + '</blockquote>\n';
        continue;
      }

      // paragraph
      if (cap = block.paragraph.exec(src)) {
        src = src.substring(cap[0].length);
        const text = cap[1].trim();
        out += '<p>' + parseInline(text) + '</p>\n';
        continue;
      }

      // text (fallback)
      if (cap = block.text.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<p>' + parseInline(cap[0]) + '</p>\n';
        continue;
      }

      if (src) {
        throw new Error('Infinite loop on byte: ' + src.charCodeAt(0));
      }
    }

    return out;
  }

  return { parse };
})();

export default marked;

